# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template

app = Flask(__name__)

@app.route('/')
def welcome():
    name = request.args.get('name', 'Anonymous')
    bio = request.args.get('bio', '')
    location = request.args.get('location', '')
    status = request.args.get('status', '')

    formatted_bio = format_text(bio)
    formatted_status = format_text(status)

    return render_template('welcome.html', name=name, bio=formatted_bio, location=location, status=formatted_status)

def format_text(text):
    # Add basic text formatting like bold or italic text here using HTML entities.
    # For example:
    text = text.replace('*bold*', '<b>bold</b>')
    text = text.replace('_italic_', '<i>italic</i>')
    return text

if __name__ == '__main__':
    app.run(debug=True)